import org.owasp.encoder.Encode;

import java.io.IOException;
import java.io.PrintWriter;

public class XssSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly encode user input before outputting it to the HTML page
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>XSS Secure Code</title></head>");
        out.println("<body>");
        out.println("<h1>Hello, " + Encode.forHtml(userInput) + "</h1>");
        out.println("</body>");
        out.println("</html>");

    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
